/** All provinces (and Metro Manila), alphabetical. */
export const PROVINCES: string[] = Object.keys(PH_LOCATIONS);

/** Cities / municipalities in a province, alphabetical. */
export function citiesOf(province: string): string[] {
  const p = PH_LOCATIONS[province];
  return p ? Object.keys(p) : [];
}

/** Known zip code(s) for a city in a province. */
export function zipsOf(province: string, city: string): string[] {
  return PH_LOCATIONS[province]?.[city] ?? [];
}
